// EP-129: compute c_r from Steiner-triple-system heuristic bound.
{
  function c_r(r) {
    return (1 / 6) * Math.log(1 / (1 - 1 / (r ** 3)));
  }
  const rows = [2, 3, 4, 5].map((r) => ({
    r,
    c_r: Number(c_r(r).toPrecision(8)),
  }));

  out.results.ep129 = {
    description: 'Computed c_r = (1/6) log(1/(1-r^{-3})) from STS-based lower bound.',
    rows,
  };
}
